INSERT INTO public.indicators (code, name, pillar, theme, description, unit, direction, normalization, min_ref, max_ref, weight, data_source, collection_type, indicator_scope, minimum_tier, benchmark_min, benchmark_max, benchmark_target, collection_frequency, source) SELECT ei.code, ei.name, ei.pillar::pillar_type, COALESCE(c.name, 'Enterprise'), ei.description, ei.unit, 'HIGH_IS_BETTER'::indicator_direction, 'MIN_MAX'::normalization_type, ei.benchmark_min::float, ei.benchmark_max::float, ei.weight, 'CALCULATED'::data_source, 'AUTOMATICA'::collection_type, 'enterprise'::indicator_scope_type, COALESCE(ei.minimum_tier, 'COMPLETE')::diagnosis_tier_type, ei.benchmark_min, ei.benchmark_max, ei.benchmark_target, COALESCE(ei.collection_frequency, 'annual'), 'Enterprise Auto-fill' FROM public.enterprise_indicators ei LEFT JOIN public.enterprise_indicator_categories c ON c.id = ei.category_id WHERE ei.is_active = true AND NOT EXISTS (SELECT 1 FROM public.indicators i WHERE i.code = ei.code) AND ei.code LIKE 'ENT_%';